using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    public TestContext TestContext { get; set; } = null!;

    private readonly PriceCalculator _calculator = new();

    [TestMethod]
    public void CalculateTotal_WithValidInputs_ReturnsSubtotalPlusTax()
    {
        var result = _calculator.CalculateTotal(10m, 2, 0.1m);
        Assert.AreEqual(22m, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
    }

    [TestMethod]
    public void FormatPrice_DefaultCurrency_ReturnsFormattedString()
    {
        var result = _calculator.FormatPrice(9.99m);
        Assert.IsInstanceOfType<string>(result);
        Assert.That.Contains(result, "9.99");
    }

    [TestMethod]
    [DataRow(100, 10, 90)]
    [DataRow(200, 25, 150)]
    public void ApplyDiscount_ValidInputs_ReturnsDiscountedPrice(
        double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }
}

